const raw = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;
if (!body.job_id) throw new Error('Payload missing: job_id');
if (!Array.isArray(body.clip_prompts) || body.clip_prompts.length !== 3) throw new Error('Payload must have clip_prompts array of 3');
return [{ json: {
  job_id: body.job_id,
  topic: body.topic,
  title: body.title,
  hashtags: body.hashtags,
  narration: body.narration,
  clip_prompts: body.clip_prompts,
  audio_path: body.audio_path,
  subs_path: body.subs_path,
  audio_duration: body.audio_duration,
  subtitle_chunks: body.subtitle_chunks,
  sheet_row: body.sheet_row || null,
  start_time: body.start_time || Date.now()
} }];

const { execSync } = require('child_process');
const fs = require('fs');

const data = $input.first().json;
const jobId = data.job_id;
const videoUrls = data.video_urls;
const subtitleChunks = data.subtitle_chunks || [];

// Ensure input dir exists on n8n side
const inputDir = '/data/ffmpeg/input';
if (!fs.existsSync(inputDir)) fs.mkdirSync(inputDir, { recursive: true });
const outputDir = '/data/ffmpeg/output';
if (!fs.existsSync(outputDir)) fs.mkdirSync(outputDir, { recursive: true });

// 1. Download 3 video clips via ffmpeg-runner container
for (let i = 0; i < videoUrls.length; i++) {
  const url = videoUrls[i];
  const outPath = '/ffmpeg/input/' + jobId + '_clip' + i + '.mp4';
  console.log('Downloading clip ' + i + ' from ' + url);
  let dlOut = '';
  try {
    dlOut = execSync(
      'docker exec ffmpeg-runner curl -sL -o "' + outPath + '" "' + url + '" && echo "DL_OK"',
      { encoding: 'utf-8', timeout: 120000 }
    );
  } catch(err) {
    dlOut = (err.stdout || err.message || '').toString();
  }
  if (!dlOut.includes('DL_OK')) throw new Error('Download failed for clip ' + i + ': ' + dlOut.slice(-300));
  console.log('Downloaded clip ' + i);
}

// 2. Create concat list file (written from n8n side to /data/ffmpeg/input/)
const concatLines = videoUrls.map((_, i) => "file '/ffmpeg/input/" + jobId + '_clip' + i + ".mp4'").join('\n');
const concatN8nPath = '/data/ffmpeg/input/' + jobId + '_concat.txt';
fs.writeFileSync(concatN8nPath, concatLines, 'utf-8');
console.log('Wrote concat file: ' + concatN8nPath);

// 3. Generate SRT file from subtitle_chunks (written from n8n side)
function toSrtTime(sec) {
  const h = Math.floor(sec / 3600);
  const m = Math.floor((sec % 3600) / 60);
  const s = Math.floor(sec % 60);
  const ms = Math.round((sec % 1) * 1000);
  return String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0') + ':' + String(s).padStart(2,'0') + ',' + String(ms).padStart(3,'0');
}

let srtContent = '';
for (let i = 0; i < subtitleChunks.length; i++) {
  const chunk = subtitleChunks[i];
  srtContent += (i + 1) + '\n';
  srtContent += toSrtTime(chunk.start) + ' --> ' + toSrtTime(chunk.end) + '\n';
  srtContent += chunk.text + '\n\n';
}

const srtN8nPath = '/data/ffmpeg/input/' + jobId + '.srt';
fs.writeFileSync(srtN8nPath, srtContent, 'utf-8');
console.log('Wrote SRT file: ' + srtN8nPath);

// 4. Run FFmpeg concat inside ffmpeg-runner container
const concatContPath = '/ffmpeg/input/' + jobId + '_concat.txt';
const concatOutContPath = '/ffmpeg/input/' + jobId + '_concat.mp4';

let concatOut = '';
try {
  concatOut = execSync(
    'docker exec ffmpeg-runner ffmpeg -y -f concat -safe 0 -i "' + concatContPath + '" -c copy "' + concatOutContPath + '" 2>&1 && echo "CONCAT_OK"',
    { encoding: 'utf-8', timeout: 300000 }
  );
} catch(err) {
  concatOut = (err.stdout || err.message || '').toString();
}
if (!concatOut.includes('CONCAT_OK')) throw new Error('FFmpeg concat failed:\n' + concatOut.slice(-600));
console.log('Concat complete');

// 5. Final assembly: concat mp4 + narration audio + burned subtitles
const srtContPath = '/ffmpeg/input/' + jobId + '.srt';
const audioContPath = '/ffmpeg/input/' + jobId + '_narration.mp3';
const finalContPath = '/ffmpeg/output/' + jobId + '_final.mp4';

const subtitleFilter = "subtitles='" + srtContPath + "':force_style='FontSize=20,Alignment=2,PrimaryColour=&H00FFFFFF,OutlineColour=&H00000000,Outline=2,Bold=1'";

let assembleOut = '';
try {
  assembleOut = execSync(
    'docker exec ffmpeg-runner ffmpeg -y -i "' + concatOutContPath + '" -i "' + audioContPath + '" -vf "' + subtitleFilter + '" -c:v libx264 -crf 23 -preset fast -c:a aac -b:a 128k -shortest "' + finalContPath + '" 2>&1 && echo "ASSEMBLE_OK"',
    { encoding: 'utf-8', timeout: 600000 }
  );
} catch(err) {
  assembleOut = (err.stdout || err.message || '').toString();
}
if (!assembleOut.includes('ASSEMBLE_OK')) throw new Error('FFmpeg final assembly failed:\n' + assembleOut.slice(-800));
console.log('Final assembly complete');

const finalN8nPath = '/data/ffmpeg/output/' + jobId + '_final.mp4';
if (!fs.existsSync(finalN8nPath)) throw new Error('Final video not found at: ' + finalN8nPath);

return [{ json: { ...data, output_filename: jobId + '_final.mp4', final_video_path: finalN8nPath } }];

const fs = require('fs');
const item = $input.first().json;
const filePath = item.final_video_path;

if (!fs.existsSync(filePath)) {
  throw new Error('Final video not found at: ' + filePath);
}

const buffer = fs.readFileSync(filePath);

return [{
  json: item,
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'video/mp4',
      fileName: item.output_filename,
      fileExtension: 'mp4'
    }
  }
}];

const driveNode   = $('Upload Animation to Drive').first().json;
const assembleData = $('Assemble Video').first().json;
const extractData  = $('Extract Payload').first().json;
const fileId = driveNode.id;

const videoUrl       = 'https://drive.google.com/uc?export=download&id=' + fileId;
const renderTimeSec  = Math.round((Date.now() - assembleData.start_time) / 1000);

console.log('Stage 2 complete. Job: ' + assembleData.job_id + ', Drive file: ' + fileId + ', Time: ' + renderTimeSec + 's');

return [{ json: {
  job_id:             assembleData.job_id,
  topic:              assembleData.topic,
  title:              assembleData.title,
  video_url:          videoUrl,
  drive_file_id:      fileId,
  render_time_seconds: renderTimeSec,
  sheet_row:          extractData.sheet_row,
  status:             'stage2_complete'
} }];

const https = require('https');
const data = $input.first().json;
const apiKey = $env.WAVESPEED_API_KEY;
const clipPrompts = data.clip_prompts;

if (!Array.isArray(clipPrompts) || clipPrompts.length === 0)
  throw new Error('No clip_prompts in payload');

function apiPost(body) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(JSON.stringify(body));
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/bytedance/seedance-1-lite/text-to-video',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Content-Type': 'application/json',
        'Content-Length': buf.length
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(JSON.parse(Buffer.concat(chunks).toString())));
    });
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

// Submit all 3 clips to Wavespeed
const task_ids = [];
for (let i = 0; i < clipPrompts.length; i++) {
  const r = await apiPost({
    prompt: clipPrompts[i],
    aspect_ratio: '9:16',
    duration: 10,
    resolution: '720p',
    generate_audio: false,
    seed: -1
  });
  if (!r.data || !r.data.id)
    throw new Error('Wavespeed submit failed clip ' + i + ': ' + JSON.stringify(r));
  task_ids.push(r.data.id);
  console.log('Clip ' + i + ' submitted — id: ' + r.data.id);
}

console.log('All 3 clips submitted. Waiting for generation...');

return [{ json: {
  ...data,
  task_ids,
  video_urls: [null, null, null],
  poll_attempt: 0,
  all_done: false
}}];

const https = require('https');
const data = $input.first().json;
const apiKey = $env.WAVESPEED_API_KEY;
const task_ids   = data.task_ids;
const video_urls = [...(data.video_urls || [null, null, null])];
const attempt    = (data.poll_attempt || 0) + 1;

console.log('--- Poll attempt #' + attempt + ' ---');

function apiGet(taskId) {
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/predictions/' + taskId,
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + apiKey }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(JSON.parse(Buffer.concat(chunks).toString())));
    });
    req.on('error', reject);
    req.end();
  });
}

// Check each clip that is not yet complete
for (let i = 0; i < task_ids.length; i++) {
  if (video_urls[i] !== null) {
    console.log('Clip ' + i + ' already done, skipping');
    continue;
  }

  const r = await apiGet(task_ids[i]);
  const status = (r.data && r.data.status) || 'unknown';
  console.log('Clip ' + i + ' [' + task_ids[i] + '] status: ' + status);

  if (status === 'completed') {
    const url = r.data.outputs && r.data.outputs[0];
    if (!url) throw new Error('Clip ' + i + ' completed but output URL missing');
    video_urls[i] = url;
    console.log('Clip ' + i + ' ready: ' + url);
  } else if (status === 'failed') {
    throw new Error('Clip ' + i + ' FAILED: ' + JSON.stringify(r.data));
  } else {
    console.log('Clip ' + i + ' still ' + status + ' — will retry in 20s');
  }
}

const all_done = video_urls.every(u => u !== null);
const pending  = video_urls.filter(u => u === null).length;

if (all_done) {
  console.log('All 3 clips are ready! Proceeding to assembly.');
} else {
  console.log(pending + ' clip(s) still generating. Waiting 20s before next poll.');
}

return [{ json: {
  ...data,
  task_ids,
  video_urls,
  poll_attempt: attempt,
  all_done
}}];
